import{c as i,Q as a,j as r,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Step-Back Profiling: Distilling User History for Personalized Scientific Writing","description":"","frontmatter":{"title":"Step-Back Profiling: Distilling User History for Personalized Scientific Writing","arxiv_id":2406.14275,"authors":"Xiangru Tang, Xingyao Zhang, Yanjun Shao, Jie Wu, Yilun Zhao, Arman Cohan, Ming Gong, Dongmei Zhang, Mark Gerstein","published":"2024-06-20T00:00:00.000Z","source":"https://arxiv.org/abs/2406.14275","venue":"arXiv"},"headers":[],"relativePath":"research/papers/2024-06-20-step-back-profiling-personalized-scientific-writing-2406.14275.md","filePath":"research/papers/2024-06-20-step-back-profiling-personalized-scientific-writing-2406.14275.md","lastUpdated":1779901665000}'),n={name:"research/papers/2024-06-20-step-back-profiling-personalized-scientific-writing-2406.14275.md"};function s(o,e,l,c,h,p){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="step-back-profiling-distilling-user-history-for-personalized-scientific-writing" tabindex="-1">Step-Back Profiling: Distilling User History for Personalized Scientific Writing <a class="header-anchor" href="#step-back-profiling-distilling-user-history-for-personalized-scientific-writing" aria-label="Permalink to &quot;Step-Back Profiling: Distilling User History for Personalized Scientific Writing&quot;">​</a></h1><p><strong>Authors</strong>: Xiangru Tang, Xingyao Zhang, Yanjun Shao, Jie Wu, Yilun Zhao, Arman Cohan, Ming Gong, Dongmei Zhang, Mark Gerstein</p><p><strong>Published</strong>: June 20, 2024 (revised July 11, 2024)</p><p><strong>Source</strong>: <a href="https://arxiv.org/abs/2406.14275" target="_blank" rel="noreferrer">https://arxiv.org/abs/2406.14275</a></p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The researchers present a method to enhance language model personalization by condensing user history into focused profiles capturing key traits and preferences. They developed a Personalized Scientific Writing dataset for studying multi-user adaptation, requiring models to compose academic papers for diverse author groups. Their approach demonstrated substantial improvements, achieving gains of &quot;up to 3.6 points on the general personalization benchmark (LaMP)&quot; across seven tasks. The methodology validates how effectively user characteristics can be extracted for collaborative writing applications.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This research paper introduces <strong>Step-back Profiling</strong>, a training-free framework for personalizing large language models by condensing user histories into concise profile representations. The authors also present the <strong>Personalized Scientific Writing (PSW) dataset</strong> to evaluate multi-user personalization in collaborative research contexts.</p><hr><h2 id="key-contributions" tabindex="-1">Key Contributions <a class="header-anchor" href="#key-contributions" aria-label="Permalink to &quot;Key Contributions&quot;">​</a></h2><h3 id="core-method" tabindex="-1">Core Method <a class="header-anchor" href="#core-method" aria-label="Permalink to &quot;Core Method&quot;">​</a></h3><p>Step-back Profiling distills individual user histories into &quot;gist&quot; representations capturing high-level traits and preferences, enabling efficient multi-user personalization without extensive computation.</p><h3 id="new-dataset" tabindex="-1">New Dataset <a class="header-anchor" href="#new-dataset" aria-label="Permalink to &quot;New Dataset&quot;">​</a></h3><p>The PSW benchmark contains research papers with multiple authors, featuring five tasks:</p><ul><li>UP-0: Research interest generation</li><li>PSW-1 through PSW-4: Topic, question, abstract, and title generation</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><p>The approach achieves 3.6-point improvements on LaMP benchmarks and demonstrates superior performance in collaborative writing scenarios.</p><hr><h2 id="technical-approach" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach" aria-label="Permalink to &quot;Technical Approach&quot;">​</a></h2><p>The procedure involves four steps:</p><ol><li><strong>User Profile Gisting</strong>: Compress each user&#39;s history using an LLM-based abstraction function</li><li><strong>Multi-User Profile Concatenation</strong>: Combine individual profiles preserving author order</li><li><strong>Retrieval-Augmented Generation</strong> (optional): Retrieve relevant historical snippets</li><li><strong>Personalized Output Generation</strong>: Condition LLM on augmented input and profiles</li></ol><hr><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="lamp-tasks" tabindex="-1">LaMP Tasks <a class="header-anchor" href="#lamp-tasks" aria-label="Permalink to &quot;LaMP Tasks&quot;">​</a></h3><ul><li>12.6% accuracy gains and 42.5% MAE reduction on classification tasks</li><li>15.2% ROUGE-1 and 19.5% ROUGE-L improvements on generation tasks</li></ul><h3 id="psw-tasks" tabindex="-1">PSW Tasks <a class="header-anchor" href="#psw-tasks" aria-label="Permalink to &quot;PSW Tasks&quot;">​</a></h3><ul><li>Multi-author setting consistently outperforms single-author and zero-shot baselines across all metrics</li></ul><hr><h2 id="notable-findings" tabindex="-1">Notable Findings <a class="header-anchor" href="#notable-findings" aria-label="Permalink to &quot;Notable Findings&quot;">​</a></h2><p>Author order significantly impacts performance—preserving original author sequence maintains expertise representation better than random shuffling. User profiles prove essential, with profile removal causing substantial performance degradation.</p><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>This work addresses a significant challenge in making large language models more responsive to individual needs within specialized domains. The dataset and implementation code are publicly available, supporting reproducibility and further research in personalized AI systems.</p>',35)])])}const g=i(n,[["render",s]]);export{u as __pageData,g as default};
